import{_ as e,o as r,c as t,a0 as h}from"./chunks/framework.jwovEGr5.js";const b=JSON.parse('{"title":"chaoxing 学习通逆向修改教程","description":"","frontmatter":{"title":"chaoxing 学习通逆向修改教程","editLink":false},"headers":[],"relativePath":"index.md","filePath":"index.md"}'),p={name:"index.md"};function n(l,a,o,i,s,c){return r(),t("div",null,[...a[0]||(a[0]=[h(`<h1 id="chaoxing-by-qcxs" tabindex="-1">chaoxing by qcxs <a class="header-anchor" href="#chaoxing-by-qcxs" aria-label="Permalink to &quot;chaoxing by qcxs&quot;">​</a></h1><h2 id="引言" tabindex="-1">引言 <a class="header-anchor" href="#引言" aria-label="Permalink to &quot;引言&quot;">​</a></h2><p>此仓库详细记录了使用<a href="https://mt2.cn/" target="_blank" rel="noreferrer">MT管理器</a>修改超星<a href="https://app.chaoxing.com/" target="_blank" rel="noreferrer">学习通</a>6.7.2版本具体流程，在此之前，全网中<strong>只</strong>找到<strong>可以拖动进度条</strong>的4.3.4版本和<a href="https://bbs.binmt.cc/thread-980-1-1.html" target="_blank" rel="noreferrer">【原创教程】学习通(超星泛雅)网络课软件破解</a>，可见相关资源匮乏。</p><p>注：有些操作需要MT会员，可使用<a href="http://normalplayer.top/" target="_blank" rel="noreferrer">NP管理器 - 功能丰富的Android文件管理APP</a>代替，阅读此教程需要一定的逆向知识，有问题问ai，可使用<a href="https://www.trae.cn/" target="_blank" rel="noreferrer">TRAE</a>打开项目，让它给你总结。</p><h2 id="使用教程" tabindex="-1">使用教程 <a class="header-anchor" href="#使用教程" aria-label="Permalink to &quot;使用教程&quot;">​</a></h2><p>直接向下阅读，点击超链接即可。</p><h2 id="推荐" tabindex="-1">推荐 <a class="header-anchor" href="#推荐" aria-label="Permalink to &quot;推荐&quot;">​</a></h2><p>由于ProGuard的混淆缘故，即使知道怎么修改，不同版本修改的位置也不一样。但是现在是ai的时代，除了<a href="/app修改/脱壳修复/脱壳修复.html">脱壳修复</a>需要手动操作外，其他的分析都可以交给ai来做，ai可以快速帮你定位和提供修改意见，你只需验证方法是否可用（如果你懂hook、xposed，甚至可以不修改apk快速得到效果）。</p><p>再此推荐两个mcp：</p><ul><li>MT mcp：<a href="https://mt2.cn/guide/reverse/apk-mcp.html" target="_blank" rel="noreferrer">APK MCP</a>，适合手机使用</li><li>jadx mcp：<a href="https://github.com/zinja-coder/jadx-ai-mcp/releases" target="_blank" rel="noreferrer">Releases · zinja-coder/jadx-ai-mcp</a>，适合电脑使用</li></ul><h2 id="通用提示词" tabindex="-1">通用提示词 <a class="header-anchor" href="#通用提示词" aria-label="Permalink to &quot;通用提示词&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span># 1、先让ai了解项目</span></span>
<span class="line"><span>调用jadx/mt mcp服务，打开apk，了解apk信息</span></span>
<span class="line"><span># 2、限定ai给出的修改意见，目前mcp提供的修改功能都不好用，推荐自行修改</span></span>
<span class="line"><span>你无需修改，只负责提供意见。修改意见：反编译代码并不好修改，常用的修改方案有更改某处判断（只需更改某行代码）、清空某个方法（阻止方法执行）、修改方法返回值（只需在末尾添加一行代码，且只限基本类型），像在中间添加调用方法等，也可以使用但比较麻烦，因为涉及到smali的寄存器，所以优先级并不高。</span></span></code></pre></div><h2 id="研究成果" tabindex="-1">研究成果 <a class="header-anchor" href="#研究成果" aria-label="Permalink to &quot;研究成果&quot;">​</a></h2><h3 id="app修改" tabindex="-1">app修改 <a class="header-anchor" href="#app修改" aria-label="Permalink to &quot;app修改&quot;">​</a></h3><h4 id="脱壳修复" tabindex="-1">脱壳修复 <a class="header-anchor" href="#脱壳修复" aria-label="Permalink to &quot;脱壳修复&quot;">​</a></h4><p><a href="/app修改/脱壳修复/脱壳修复.html">脱壳修复</a></p><p>参考网上大佬对<strong>棒棒加固企业版</strong>的处理过程。</p><h4 id="章节视频" tabindex="-1">章节视频 <a class="header-anchor" href="#章节视频" aria-label="Permalink to &quot;章节视频&quot;">​</a></h4><p><a href="/app修改/章节视频/章节视频快进、倍速.html">章节视频快进、倍速</a></p><p>app播放器默认没有快进、倍速限制，只需阻止服务器向app传输命令即可去除。但是请注意，时长不够仍不能判定为完成学习，故更推荐使用电脑插件挂机刷。此处修改只是个人喜好。</p><h4 id="多端登录" tabindex="-1">多端登录 <a class="header-anchor" href="#多端登录" aria-label="Permalink to &quot;多端登录&quot;">​</a></h4><p>方案一：可以<a href="/app修改/多端登录/不理会下线.html">不理会下线</a>，但仍会把其他版本挤下线。</p><p>方案二：在一次修改中误打误撞发现，<a href="/app修改/多端登录/阻止挤别人下线.html">阻止挤别人下线</a>办法，但会造成消息功能不能使用。故推荐共存时修改，但日用时不要修改。</p><h4 id="开屏广告" tabindex="-1">开屏广告 <a class="header-anchor" href="#开屏广告" aria-label="Permalink to &quot;开屏广告&quot;">​</a></h4><p><a href="/app修改/开屏广告/去除开屏广告.html">去除开屏广告</a></p><p>很简单，activity记录找到开屏类，发现一个的AD类，让其返回为空即可。</p><h4 id="去除更新" tabindex="-1">去除更新 <a class="header-anchor" href="#去除更新" aria-label="Permalink to &quot;去除更新&quot;">​</a></h4><p><a href="/app修改/去除更新/去除更新.html">去除更新</a></p><h4 id="我学的课" tabindex="-1">我学的课 <a class="header-anchor" href="#我学的课" aria-label="Permalink to &quot;我学的课&quot;">​</a></h4><p><a href="/app修改/我学的课/默认我学的课.html">默认我学的课</a></p><p>楼主喜欢在课程列表中查看课程，但是默认进入的是<strong>我教的课</strong>，而不是<strong>我学的课</strong>，图省事写死。</p><h3 id="全栈修改" tabindex="-1">全栈修改 <a class="header-anchor" href="#全栈修改" aria-label="Permalink to &quot;全栈修改&quot;">​</a></h3><p>偶然间，发现app会执行javascript:js代码，并且作业、章节测验、考试等页面是一个网页，对它们的修改使用js更方便，故<a href="/app修改/转交战场/添加自定义js.html">添加自定义js</a>，又为了方便调试网页<a href="/app修改/转交战场/默认开启网页调试.html">默认开启网页调试</a>。</p><h3 id="jsbridge" tabindex="-1">jsBridge <a class="header-anchor" href="#jsbridge" aria-label="Permalink to &quot;jsBridge&quot;">​</a></h3><p>网页通过jsBridge与app进行交互。</p><p>例如：<a href="/app修改/考试脱控/考试脱控.html">考试脱控</a>，考试页面本质上只是一个网页，app默认没有切屏检测，于是可以通过不理会交互达成脱控目的。</p><p>在app.js中，化敌为友，通过此特性，将其当做api进行调用，可以添加许多功能，详细请阅读：<a href="/appjs/appjs使用教程.html">appjs使用教程</a>。</p><h2 id="其他教程" tabindex="-1">其他教程 <a class="header-anchor" href="#其他教程" aria-label="Permalink to &quot;其他教程&quot;">​</a></h2><h3 id="app修改-1" tabindex="-1">app修改 <a class="header-anchor" href="#app修改-1" aria-label="Permalink to &quot;app修改&quot;">​</a></h3><h4 id="初版教程" tabindex="-1">初版教程 <a class="header-anchor" href="#初版教程" aria-label="Permalink to &quot;初版教程&quot;">​</a></h4><p><a href="https://bbs.binmt.cc/thread-145359-1-1.html" target="_blank" rel="noreferrer">学习通修改教程终版</a></p><h3 id="网页调试教程" tabindex="-1">网页调试教程 <a class="header-anchor" href="#网页调试教程" aria-label="Permalink to &quot;网页调试教程&quot;">​</a></h3><p><a href="https://bbs.binmt.cc/thread-150946-1-1.html" target="_blank" rel="noreferrer">一个简单的web调试逆向</a></p><p><a href="https://bbs.binmt.cc/thread-160969-1-1.html" target="_blank" rel="noreferrer">adb远程调试网页</a></p><h3 id="位置签到解析" tabindex="-1">位置签到解析 <a class="header-anchor" href="#位置签到解析" aria-label="Permalink to &quot;位置签到解析&quot;">​</a></h3><p><a href="https://bbs.binmt.cc/thread-157986-1-1.html" target="_blank" rel="noreferrer">学习通伪造位置签到</a></p><h3 id="填空题粘贴" tabindex="-1">填空题粘贴 <a class="header-anchor" href="#填空题粘贴" aria-label="Permalink to &quot;填空题粘贴&quot;">​</a></h3><p><a href="https://bbs.binmt.cc/thread-151654-1-1.html" target="_blank" rel="noreferrer">学习通网页复制文字-粘贴图片-油猴插件代码</a></p><h2 id="资料" tabindex="-1">资料 <a class="header-anchor" href="#资料" aria-label="Permalink to &quot;资料&quot;">​</a></h2><p><a href="https://www.123684.com/s/o1cqVv-a1hjH" target="_blank" rel="noreferrer">https://www.123684.com/s/o1cqVv-a1hjH</a></p><h2 id="友链" tabindex="-1">友链 <a class="header-anchor" href="#友链" aria-label="Permalink to &quot;友链&quot;">​</a></h2><p>学习通微信版（网页）：<a href="https://mooc1.chaoxing.com/course/phone/courselisthead" target="_blank" rel="noreferrer">https://mooc1.chaoxing.com/course/phone/courselisthead</a></p>`,52)])])}const m=e(p,[["render",n]]);export{b as __pageData,m as default};
